import{_ as t,o as l,c as e,a2 as i}from"./chunks/framework.Cr-Z7ngm.js";const b=JSON.parse('{"title":"自定义布局","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/desktop-tools/custom-layout.md","filePath":"zh-CN/stock-trading/desktop-tools/custom-layout.md"}'),r={name:"stock-trading/desktop-tools/custom-layout.md"};function o(d,a,h,n,s,u){return l(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="自定义布局" tabindex="-1">自定义布局 <a class="header-anchor" href="#自定义布局" aria-label="Permalink to &quot;自定义布局&quot;">​</a></h1><p>组件操作、联动设置、系统和自定义布局类型、布局保存及组件拼接。</p><h2 id="组件概念" tabindex="-1">组件概念 <a class="header-anchor" href="#组件概念" aria-label="Permalink to &quot;组件概念&quot;">​</a></h2><p>桌面端所有功能均以&quot;组件&quot;形式存在。用户可从组件工具箱中添加所需组件，自由搭建个人工作台。</p><h2 id="组件基本操作" tabindex="-1">组件基本操作 <a class="header-anchor" href="#组件基本操作" aria-label="Permalink to &quot;组件基本操作&quot;">​</a></h2><ul><li>添加：点击组件工具箱，选择目标组件拖入布局区域</li><li>调整大小：拖动组件边缘改变宽高</li><li>复制：通过组件菜单复制当前组件及其配置</li><li>最大化：将组件临时扩展至全屏</li><li>脱离：将组件从当前布局中独立为浮动窗口</li><li>移除：从布局中删除该组件</li></ul><h2 id="组件联动" tabindex="-1">组件联动 <a class="header-anchor" href="#组件联动" aria-label="Permalink to &quot;组件联动&quot;">​</a></h2><p>组件间支持股票或市场联动，切换一个组件的标的时，其他联动组件同步切换。</p><p>联动分组设置：</p><ul><li>默认：参与默认联动组</li><li>不联动：该组件独立，不随其他组件变化</li><li>分组 1-9：自定义分组，同组组件之间互相联动</li></ul><p>支持双向联动，即任意一个组件切换标的时，同组其他组件均同步响应。</p><h2 id="组件头部功能" tabindex="-1">组件头部功能 <a class="header-anchor" href="#组件头部功能" aria-label="Permalink to &quot;组件头部功能&quot;">​</a></h2><ul><li>搜索：在组件头部直接搜索股票或切换标的</li><li>钉住置顶：将组件窗口固定在最顶层，防止被其他窗口遮挡</li></ul><h2 id="布局类型" tabindex="-1">布局类型 <a class="header-anchor" href="#布局类型" aria-label="Permalink to &quot;布局类型&quot;">​</a></h2><h3 id="系统布局" tabindex="-1">系统布局 <a class="header-anchor" href="#系统布局" aria-label="Permalink to &quot;系统布局&quot;">​</a></h3><p>预设布局，不可删除，但可重置为默认配置。</p><h3 id="自定义布局-1" tabindex="-1">自定义布局 <a class="header-anchor" href="#自定义布局-1" aria-label="Permalink to &quot;自定义布局&quot;">​</a></h3><p>用户自行创建的布局，支持两种形式：</p><table tabindex="0"><thead><tr><th>对比项</th><th>自适应布局</th><th>画布布局</th></tr></thead><tbody><tr><td>定位方式</td><td>流式，动态调整</td><td>固定像素，绝对定位</td></tr><tr><td>多屏适配</td><td>自动适配不同分辨率</td><td>固定尺寸，不自动适配</td></tr><tr><td>自由度</td><td>较低</td><td>高，可任意放置</td></tr><tr><td>适用场景</td><td>常规使用、多屏切换</td><td>固定工作站、精细布局</td></tr></tbody></table><h3 id="画布布局专属功能" tabindex="-1">画布布局专属功能 <a class="header-anchor" href="#画布布局专属功能" aria-label="Permalink to &quot;画布布局专属功能&quot;">​</a></h3><ul><li>锁定/解锁：锁定后组件位置固定，防止误操作移动</li><li>磁吸对齐：拖动组件时自动对齐到其他组件边缘或网格线</li></ul><h2 id="布局保存" tabindex="-1">布局保存 <a class="header-anchor" href="#布局保存" aria-label="Permalink to &quot;布局保存&quot;">​</a></h2><ul><li>云端自动保存：布局变更实时同步到云端，换设备登录后自动恢复</li><li>手动保存：支持手动保存当前布局快照，最多保存 20 条历史版本</li></ul><h2 id="组件拼接" tabindex="-1">组件拼接 <a class="header-anchor" href="#组件拼接" aria-label="Permalink to &quot;组件拼接&quot;">​</a></h2><p>组件拼接允许在同一个区域内通过 Tab 页切换多个组件，有效节省屏幕空间。</p><h3 id="使用场景" tabindex="-1">使用场景 <a class="header-anchor" href="#使用场景" aria-label="Permalink to &quot;使用场景&quot;">​</a></h3><p>适合将多个相关组件（如行情、资讯、财报）集中在同一位置，按需切换查看。</p><h3 id="操作说明" tabindex="-1">操作说明 <a class="header-anchor" href="#操作说明" aria-label="Permalink to &quot;操作说明&quot;">​</a></h3><p>将一个组件拖动到另一个组件上，当出现阴影色块提示时松开，即完成拼接。</p><h3 id="其他操作" tabindex="-1">其他操作 <a class="header-anchor" href="#其他操作" aria-label="Permalink to &quot;其他操作&quot;">​</a></h3><ul><li>调整 Tab 顺序：拖动 Tab 标签可改变显示顺序</li><li>移除组件：右键 Tab 标签选择移除，或拖出 Tab 区域脱离拼接</li><li>脱离拼接：拖动 Tab 标签到布局空白区域，使其成为独立组件</li></ul><h3 id="限制" tabindex="-1">限制 <a class="header-anchor" href="#限制" aria-label="Permalink to &quot;限制&quot;">​</a></h3><p>同一页面最多可拼接 15 个组件。</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/stock-trading/桌面端工具/市场深度">市场深度</a> — 桌面端工具</li><li><a href="/stock-trading/桌面端工具/图表交易">图表交易</a> — 桌面端交易工具</li></ul>',35)])])}const p=t(r,[["render",o]]);export{b as __pageData,p as default};
